const LS_WRONG = "medApp_wrongIds";
const LS_HISTORY = "medApp_history";
const LS_PROGRESS = "medApp_progress"; // {mode: string, index: number}
const LS_STAR = "medApp_starIds";

// ============================================================
// 音声解説ファイル設定
// ※ public/audio/ フォルダに m4a ファイルを置いてください
// ============================================================

// ============================================================
// ユーティリティ
// ============================================================
function loadStarIds() {
  try { return new Set(JSON.parse(localStorage.getItem(LS_STAR) || "[]")); }
  catch { return new Set(); }
}
function saveStarIds(set) {
  localStorage.setItem(LS_STAR, JSON.stringify([...set]));
}

function loadWrongIds() {
  try { return new Set(JSON.parse(localStorage.getItem(LS_WRONG) || "[]")); }
  catch { return new Set(); }
}
function saveWrongIds(set) {
  localStorage.setItem(LS_WRONG, JSON.stringify([...set]));
}
function loadHistory() {
  try { return JSON.parse(localStorage.getItem(LS_HISTORY) || "{}"); }
  catch { return {}; }
}
function saveHistory(h) {
  localStorage.setItem(LS_HISTORY, JSON.stringify(h));
}
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
function buildQueue(mode, allQuestions, wrongIds, starIds = new Set()) {
  const byNumber = (a, b) => a.number - b.number || a.id.localeCompare(b.id);
  if (mode === "year2024") {
    return allQuestions.filter((q) => q.year === "2024").sort(byNumber);
  }
  if (mode === "year2023") {
    return allQuestions.filter((q) => q.year === "2023").sort(byNumber);
  }
  if (mode === "year2022") {
    return allQuestions.filter((q) => q.year === "2022").sort(byNumber);
  }
  if (mode === "year2021") {
    return allQuestions.filter((q) => q.year === "2021").sort(byNumber);
  }
  if (mode === "random") return shuffle(allQuestions).slice(0, 10);
  if (mode === "review") {
    const wrong = allQuestions.filter((q) => wrongIds.has(q.id));
    return wrong.length > 0 ? shuffle(wrong) : [];
  }
  if (mode === "star") {
    const starred = allQuestions.filter((q) => starIds.has(q.id));
    return starred.length > 0 ? shuffle(starred) : [];
  }
  if (mode.startsWith("cat:")) {
    const catName = mode.slice(4);
    return shuffle(allQuestions.filter((q) => getCategory(q) === catName));
  }
  return [];
}

// correctAnswer は number（単一）または number[]（複数）どちらでも受け付ける
// 正解インデックスのSetを返す
function getCorrectSet(q) {
  const ca = q.correctAnswer;
  if (Array.isArray(ca)) return new Set(ca);
  return new Set([ca]);
}

// 問題文から「2つ選べ」「3つ選べ」などを判定して選択数を返す
function getRequiredCount(question) {
  const m = question.question.match(/(\d+)つ選べ/);
  if (m) return parseInt(m[1]);
  if (question.question.includes("2つ")) return 2;
  if (question.question.includes("3つ")) return 3;
  // correctAnswer が配列の場合はその長さ
  if (Array.isArray(question.correctAnswer)) return question.correctAnswer.length;
  return 1;
}

// ============================================================
// 音声ユーティリティ
// ============================================================
function speak(text, onEnd) {
  if (!window.speechSynthesis) { onEnd && onEnd(); return; }
  window.speechSynthesis.cancel();
  const utter = new SpeechSynthesisUtterance(text);
  utter.lang = "ja-JP";
  utter.rate = 0.95;
  utter.pitch = 1.0;
  if (onEnd) utter.onend = onEnd;
  setTimeout(() => window.speechSynthesis.speak(utter), 100);
}
function stopSpeech() {
  if (window.speechSynthesis) window.speechSynthesis.cancel();
}

// ============================================================
// メインApp
// ============================================================
export default function App() {
  const [screen, setScreen] = useState("home");
  const [navTab, setNavTab] = useState("year"); // "year" | "category"
  const [mode, setMode] = useState(null);
  const [voiceMode, setVoiceMode] = useState(false);
  const [queue, setQueue] = useState([]);
  const [qIndex, setQIndex] = useState(0);

  // 複数選択対応: selectedSet = Set<number>
  const [selectedSet, setSelectedSet] = useState(new Set());
  // 回答確定済みかどうか
  const [confirmed, setConfirmed] = useState(false);
  const [showExplanation, setShowExplanation] = useState(false);
  const [sessionResults, setSessionResults] = useState([]);
  const [wrongIds, setWrongIds] = useState(loadWrongIds);
  const [starIds, setStarIds] = useState(loadStarIds);
  const [history, setHistory] = useState(loadHistory);

  const [voicePhase, setVoicePhase] = useState("idle");
  const [voiceListening, setVoiceListening] = useState(false);
  const [voiceError, setVoiceError] = useState("");
  const recognitionRef = useRef(null);
  const voiceTimerRef = useRef(null);

  const currentQ = queue[qIndex] || null;
  const requiredCount = currentQ ? getRequiredCount(currentQ) : 1;
  const correctSet = currentQ ? getCorrectSet(currentQ) : new Set();

  useEffect(() => {
    return () => {
      stopSpeech();
      clearTimeout(voiceTimerRef.current);
      try { recognitionRef.current?.abort(); } catch {}
    };
  }, []);

  // ============================================================
  // 開始処理
  // ============================================================
  function startQuiz(selectedMode, selectedVoice, forceRestart = false) {
    stopSpeech();
    setMode(selectedMode);
    setVoiceMode(selectedVoice);
    const q = buildQueue(selectedMode, SAMPLE_QUESTIONS, wrongIds, starIds);
    if (q.length === 0) {
      alert(selectedMode === "star" ? "⭐要確認の問題がありません。問題画面の⭐ボタンでマークしてください。" : selectedMode === "review" ? "復習問題がありません。まず問題を解いて間違えた問題を作成してください。" : "問題がありません。");
      return;
    }
    setQueue(q);
    // 前回の続きから再開（年度別モードのみ・強制リスタートでない場合）
    let startIndex = 0;
    if (!forceRestart && (selectedMode === "year2024" || selectedMode === "year2023" || selectedMode === "year2022" || selectedMode === "year2021") && !selectedMode.startsWith("cat:")) {
      try {
        const saved = JSON.parse(localStorage.getItem(LS_PROGRESS) || "{}");
        if (saved.mode === selectedMode && saved.index > 0 && saved.index < q.length) {
          startIndex = saved.index;
        }
      } catch {}
    }
    setQIndex(startIndex);
    setSelectedSet(new Set());
    setConfirmed(false);
    setShowExplanation(false);
    setSessionResults([]);
    setVoicePhase("idle");
    setVoiceError("");
    setScreen("quiz");
  }

  // ============================================================
  // 通常モード: 選択肢をタップ
  // ============================================================
  function handleToggle(idx) {
    if (confirmed) return;
    if (requiredCount === 1) {
      // 1択は即確定
      const ns = new Set([idx]);
      setSelectedSet(ns);
      confirmAnswer(ns);
    } else {
      // 複数択: トグル
      setSelectedSet((prev) => {
        const next = new Set(prev);
        if (next.has(idx)) {
          next.delete(idx);
        } else {
          if (next.size < requiredCount) next.add(idx);
        }
        return next;
      });
    }
  }

  function confirmAnswer(overrideSet) {
    const useSet = overrideSet ?? selectedSet;
    if (useSet.size === 0) return;
    setConfirmed(true);
    setShowExplanation(true);

    // 正誤判定: 選択したSetが正解Setと完全一致
    const isCorrect =
      useSet.size === correctSet.size &&
      [...useSet].every((v) => correctSet.has(v));

    recordResult(currentQ.id, isCorrect);
  }

  function recordResult(qId, correct) {
    setSessionResults((prev) => [...prev, { id: qId, correct }]);
    setWrongIds((prev) => {
      const next = new Set(prev);
      if (!correct) next.add(qId);
      saveWrongIds(next);
      return next;
    });
    setHistory((prev) => {
      const next = { ...prev };
      if (!next[qId]) next[qId] = { correct: 0, wrong: 0 };
      if (correct) next[qId].correct++;
      else next[qId].wrong++;
      saveHistory(next);
      return next;
    });
  }

  function toggleStar(qId) {
    setStarIds((prev) => {
      const next = new Set(prev);
      if (next.has(qId)) next.delete(qId);
      else next.add(qId);
      saveStarIds(next);
      return next;
    });
  }

  function goNext() {
    if (qIndex + 1 >= queue.length) {
      // 完了時は進捗をリセット
      try { localStorage.removeItem(LS_PROGRESS); } catch {}
      setScreen("result");
      return;
    }
    const nextIndex = qIndex + 1;
    // 年度別モードは進捗を保存
    if ((mode === "year2024" || mode === "year2023" || mode === "year2022" || mode === "year2021") && !mode.startsWith("cat:")) {
      try { localStorage.setItem(LS_PROGRESS, JSON.stringify({ mode, index: nextIndex })); } catch {}
    }
    setQIndex(nextIndex);
    setSelectedSet(new Set());
    setConfirmed(false);
    setShowExplanation(false);
  }

  // ============================================================
  // 音声モード: ループ制御（単一選択のみ対応）
  // ============================================================
  useEffect(() => {
    if (screen !== "quiz" || !voiceMode || !currentQ) return;
    if (voicePhase === "idle") startReadingQuestion();
  }, [screen, voiceMode, currentQ, voicePhase]);

  function startReadingQuestion() {
    setVoicePhase("reading");
    const text =
      `問題${currentQ.number}。${currentQ.question}。` +
      currentQ.options.map((o, i) => `選択肢${i + 1}、${o}`).join("。");
    speak(text, () => { setVoicePhase("listening"); startListening(); });
  }

  function startListening() {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { setVoiceError("このブラウザは音声認識に対応していません。"); setVoicePhase("idle"); return; }
    const rec = new SR();
    rec.lang = "ja-JP";
    rec.continuous = false;
    rec.interimResults = false;
    recognitionRef.current = rec;
    setVoiceListening(true);
    setVoiceError("");
    rec.onresult = (e) => { const t = e.results[0][0].transcript; handleVoiceAnswer(t); };
    rec.onerror = (e) => {
      setVoiceListening(false);
      setVoiceError(`音声認識エラー: ${e.error}。もう一度お試しください。`);
      voiceTimerRef.current = setTimeout(() => { setVoicePhase("listening"); startListening(); }, 2000);
    };
    rec.onend = () => setVoiceListening(false);
    try { rec.start(); } catch {}
  }

  function handleVoiceAnswer(transcript) {
    setVoiceListening(false);
    try { recognitionRef.current?.abort(); } catch {}
    const numMap = { "1": 0, "2": 1, "3": 2, "4": 3, "5": 4, "１": 0, "２": 1, "３": 2, "４": 3, "５": 4, "一": 0, "二": 1, "三": 2, "四": 3, "五": 4 };

    // 複数選択問題の場合: 「1と3」「2番と4番」のようなパターンを解析
    const matches = [...transcript.matchAll(/[1-5１-５一二三四五]/g)].map(m => m[0]);
    if (matches.length === 0) {
      setVoiceError(`「${transcript}」が認識できませんでした。番号を声で答えてください。`);
      voiceTimerRef.current = setTimeout(() => { setVoicePhase("listening"); startListening(); }, 2000);
      return;
    }

    const selectedIndices = [...new Set(matches.map(m => numMap[m] ?? (parseInt(m) - 1)))];
    // 必要な選択数に満たない場合は最初の1つで判定（音声は難しいため）
    const ns = new Set(selectedIndices.slice(0, requiredCount));
    setSelectedSet(ns);
    setConfirmed(true);
    setShowExplanation(true);

    const isCorrect = ns.size === correctSet.size && [...ns].every((v) => correctSet.has(v));
    recordResult(currentQ.id, isCorrect);

    setVoicePhase("feedback");
    const correctList = [...correctSet].map(i => `${i + 1}番`).join("と");
    const feedbackText = isCorrect
      ? `正解です。正解は${correctList}です。解説。${currentQ.explanation}`
      : `不正解です。正解は${correctList}です。解説。${currentQ.explanation}`;

    speak(feedbackText, () => {
      setVoicePhase("pause");
      voiceTimerRef.current = setTimeout(() => {
        if (qIndex + 1 >= queue.length) { setScreen("result"); }
        else { setQIndex((i) => i + 1); setSelectedSet(new Set()); setConfirmed(false); setShowExplanation(false); setVoicePhase("idle"); }
      }, 3000);
    });
  }

  function stopVoiceMode() {
    stopSpeech();
    clearTimeout(voiceTimerRef.current);
    try { recognitionRef.current?.abort(); } catch {}
    setVoiceMode(false);
    setVoicePhase("idle");
    setVoiceListening(false);
  }

  // ============================================================
  // 画面レンダリング
  // ============================================================
  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 font-sans">
      {screen === "home" && <HomeScreen onStart={startQuiz} wrongCount={wrongIds.size} starCount={starIds.size} navTab={navTab} onNavTab={setNavTab} />}
      {screen === "quiz" && currentQ && (
        <QuizScreen
          question={currentQ}
          qIndex={qIndex}
          total={queue.length}
          selectedSet={selectedSet}
          confirmed={confirmed}
          showExplanation={showExplanation}
          correctSet={correctSet}
          requiredCount={requiredCount}
          voiceMode={voiceMode}
          voicePhase={voicePhase}
          voiceListening={voiceListening}
          voiceError={voiceError}
          onToggle={handleToggle}
          onConfirm={() => confirmAnswer()}
          onNext={goNext}
          onStopVoice={stopVoiceMode}
          onBack={() => { stopSpeech(); clearTimeout(voiceTimerRef.current); setScreen("home"); }}
          isResume={qIndex > 0 && sessionResults.length === 0}
          onRestart={() => startQuiz(mode, false, true)}
          onJump={(idx) => { setQIndex(idx); setSelectedSet(new Set()); setConfirmed(false); setShowExplanation(false); }}
          isStarred={starIds.has(currentQ?.id)}
          onToggleStar={() => toggleStar(currentQ?.id)}
        />
      )}
      {screen === "result" && (
        <ResultScreen results={sessionResults} questions={queue}
          onHome={() => setScreen("home")} onRetry={() => startQuiz(mode, voiceMode)} />
      )}
    </div>
  );
}

