// ============================================================
// QuizScreen
// ============================================================
function QuizScreen({
  question, qIndex, total,
  selectedSet, confirmed, showExplanation, correctSet, requiredCount,
  voiceMode, voicePhase, voiceListening, voiceError,
  onToggle, onConfirm, onNext, onStopVoice, onBack, isResume, onRestart, onJump,
  isStarred, onToggleStar,
}) {
  const [jumpInput, setJumpInput] = useState("");
  const [showJump, setShowJump] = useState(false);

  function handleJump() {
    const n = parseInt(jumpInput);
    if (!isNaN(n) && n >= 1 && n <= total) {
      onJump(n - 1);
      setShowJump(false);
      setJumpInput("");
    }
  }
  // 選択済みかつ確定後の正誤
  const isCorrect = confirmed &&
    selectedSet.size === correctSet.size &&
    [...selectedSet].every((v) => correctSet.has(v));

  // 各選択肢の見た目
  const optionStyle = (idx) => {
    if (!confirmed) {
      // 未確定: 選択中はスカイブルー、未選択はデフォルト
      if (selectedSet.has(idx)) {
        return "bg-sky-500/20 border-sky-400 text-sky-200 active:scale-95";
      }
      return "bg-slate-800/70 border-slate-700 hover:bg-slate-700/80 hover:border-slate-600 active:scale-95";
    }
    // 確定後
    if (correctSet.has(idx)) return "bg-emerald-500/20 border-emerald-500 text-emerald-200";
    if (selectedSet.has(idx) && !correctSet.has(idx)) return "bg-rose-500/20 border-rose-500 text-rose-200";
    return "bg-slate-800/40 border-slate-700/40 text-slate-500";
  };

  const badgeStyle = (idx) => {
    if (!confirmed) {
      if (selectedSet.has(idx)) return "bg-sky-500 border-sky-400 text-white";
      return "bg-slate-700 border-slate-600 text-slate-300";
    }
    if (correctSet.has(idx)) return "bg-emerald-500 border-emerald-400 text-slate-900";
    if (selectedSet.has(idx) && !correctSet.has(idx)) return "bg-rose-500 border-rose-400 text-white";
    return "bg-slate-700 border-slate-600 text-slate-500";
  };

  const correctList = [...correctSet].sort().map(i => `${i + 1}番`).join("と");

  return (
    <div className="max-w-lg mx-auto px-4 py-6 pb-12">
      {/* トップバー */}
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-1">
          <button onClick={onBack} className="p-2 rounded-xl text-slate-400 hover:text-slate-200 hover:bg-slate-800 transition-colors">← 戻る</button>
          {isResume && <button onClick={onRestart} className="text-xs px-2 py-1 rounded-lg bg-slate-700 text-slate-400 hover:bg-slate-600 transition-colors">最初から</button>}
          <button onClick={onToggleStar} className={`text-2xl transition-all active:scale-95 ${isStarred ? "opacity-100" : "opacity-30"}`} title="要確認にマーク">⭐</button>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-xs bg-slate-800 border border-slate-700 rounded-lg px-2 py-1 text-slate-400">
            {question.year}年 Q{question.number}
          </span>
          <span className="text-xs text-slate-400">{qIndex + 1} / {total}</span>
        </div>
      </div>

      {/* スクラバー（スライドで問題ジャンプ） */}
      <div className="mb-5">
        <input
          type="range"
          min="0"
          max={total - 1}
          value={qIndex}
          onChange={e => {
            const idx = parseInt(e.target.value);
            onJump(idx);
          }}
          style={{
            width: "100%",
            height: "6px",
            appearance: "none",
            WebkitAppearance: "none",
            background: `linear-gradient(to right, #10b981 ${(qIndex/(total-1))*100}%, #334155 ${(qIndex/(total-1))*100}%)`,
            borderRadius: "9999px",
            outline: "none",
            cursor: "pointer",
          }}
        />
      </div>

      {/* 音声モード状態表示 */}
      {voiceMode && (
        <div className={`mb-4 p-3 rounded-xl border text-sm flex items-center gap-3 transition-all ${voiceListening ? "bg-red-500/10 border-red-500/40 text-red-300" : voicePhase === "reading" ? "bg-sky-500/10 border-sky-500/40 text-sky-300" : voicePhase === "pause" ? "bg-slate-700/40 border-slate-600 text-slate-400" : "bg-slate-800/60 border-slate-700 text-slate-400"}`}>
          {voiceListening ? (<><span className="animate-pulse text-red-400 text-lg">●</span><span>マイク録音中… 番号を声で答えてください</span></>) :
           voicePhase === "reading" ? (<><span className="animate-bounce text-sky-400 text-lg">🔊</span><span>読み上げ中…</span></>) :
           voicePhase === "feedback" ? (<><span className="text-lg">🔊</span><span>解説を読み上げ中…</span></>) :
           voicePhase === "pause" ? (<><span className="text-lg">⏳</span><span>3秒後に次の問題へ…</span></>) :
           (<><span className="text-lg">🎙️</span><span>音声モード準備中…</span></>)}
        </div>
      )}
      {voiceError && (
        <div className="mb-3 p-3 rounded-xl bg-rose-500/10 border border-rose-500/30 text-rose-300 text-sm">⚠️ {voiceError}</div>
      )}

      {/* 問題文 */}
      <div className="mb-2 p-5 rounded-2xl bg-slate-800/60 border border-slate-700/50">
        <p className="text-slate-100 text-base leading-relaxed">{question.question}</p>
      </div>

      {/* 複数選択インジケーター */}
      {requiredCount > 1 && !confirmed && (
        <div className="mb-4 flex items-center justify-between px-1">
          <p className="text-xs text-sky-400">
            {selectedSet.size} / {requiredCount} 個選択中
          </p>
          <div className="flex gap-1">
            {Array.from({ length: requiredCount }).map((_, i) => (
              <div key={i} className={`w-2.5 h-2.5 rounded-full border ${i < selectedSet.size ? "bg-sky-400 border-sky-400" : "bg-slate-700 border-slate-600"}`} />
            ))}
          </div>
        </div>
      )}

      {/* 選択肢 */}
      <div className="space-y-3 mb-5">
        {question.options.map((opt, idx) => (
          <button
            key={idx}
            onClick={() => !voiceMode && onToggle(idx)}
            disabled={confirmed || voiceMode}
            className={`w-full flex items-start gap-3 p-4 rounded-2xl border transition-all text-left ${optionStyle(idx)}`}
          >
            <span className={`flex-shrink-0 w-7 h-7 rounded-full flex items-center justify-center text-sm font-bold border transition-colors ${badgeStyle(idx)}`}>
              {idx + 1}
            </span>
            <span className="text-sm leading-relaxed">{opt}</span>
            {/* 確定後アイコン */}
            {confirmed && correctSet.has(idx) && (
              <span className="ml-auto flex-shrink-0 text-emerald-400 text-lg">✓</span>
            )}
            {confirmed && selectedSet.has(idx) && !correctSet.has(idx) && (
              <span className="ml-auto flex-shrink-0 text-rose-400 text-lg">✗</span>
            )}
            {/* 未確定・選択中のチェック */}
            {!confirmed && selectedSet.has(idx) && (
              <span className="ml-auto flex-shrink-0 text-sky-400 text-lg">✓</span>
            )}
          </button>
        ))}
      </div>

      {/* 複数選択の確定ボタン */}
      {requiredCount > 1 && !confirmed && !voiceMode && (
        <button
          onClick={onConfirm}
          disabled={selectedSet.size !== requiredCount}
          className={`w-full py-4 rounded-2xl font-bold text-base mb-4 transition-all ${
            selectedSet.size === requiredCount
              ? "bg-sky-500 hover:bg-sky-400 active:scale-95 text-white shadow-lg shadow-sky-500/20"
              : "bg-slate-700/50 border border-slate-600 text-slate-500 cursor-not-allowed"
          }`}
        >
          {selectedSet.size === requiredCount
            ? `${requiredCount}つ選択済み — 回答を確定する`
            : `あと ${requiredCount - selectedSet.size} つ選択してください`}
        </button>
      )}

      {/* 正誤バナー */}
      {confirmed && (
        <div className={`mb-4 p-4 rounded-2xl text-center font-bold text-lg ${isCorrect ? "bg-emerald-500/20 border border-emerald-500/50 text-emerald-300" : "bg-rose-500/20 border border-rose-500/50 text-rose-300"}`}>
          {isCorrect
            ? "✓ 正解！"
            : `✗ 不正解　正解は ${correctList}`}
        </div>
      )}

      {/* 解説カード */}
      {showExplanation && (
        <div className="mb-6 p-5 rounded-2xl bg-slate-800/80 border border-slate-600/60">
          <p className="text-xs font-semibold text-emerald-400 uppercase tracking-widest mb-3">📖 解説</p>
          <p className="text-slate-200 text-sm leading-relaxed">{question.explanation}</p>
        </div>
      )}

      {/* 次へボタン */}
      {confirmed && !voiceMode && (
        <button onClick={onNext} className="w-full py-5 rounded-2xl bg-emerald-500 hover:bg-emerald-400 active:scale-95 transition-all font-bold text-slate-900 text-lg shadow-lg shadow-emerald-500/20">
          次の問題へ →
        </button>
      )}
    </div>
  );
}

// ============================================================
// ResultScreen
// ============================================================
function ResultScreen({ results, questions, onHome, onRetry }) {
  const total = results.length;
  const correct = results.filter((r) => r.correct).length;
  const pct = total > 0 ? Math.round((correct / total) * 100) : 0;
  const grade =
    pct >= 90 ? { label: "優秀", color: "text-emerald-400", bg: "bg-emerald-500/20", border: "border-emerald-500/50" } :
    pct >= 70 ? { label: "合格圏", color: "text-sky-400", bg: "bg-sky-500/20", border: "border-sky-500/50" } :
    pct >= 50 ? { label: "要復習", color: "text-amber-400", bg: "bg-amber-500/20", border: "border-amber-500/50" } :
    { label: "要再学習", color: "text-rose-400", bg: "bg-rose-500/20", border: "border-rose-500/50" };
  return (
    <div className="max-w-lg mx-auto px-4 py-8 pb-12">
      <div className={`text-center p-8 rounded-3xl border mb-6 ${grade.bg} ${grade.border}`}>
        <p className="text-xs font-semibold uppercase tracking-widest text-slate-400 mb-2">セッション結果</p>
        <p className={`text-7xl font-black mb-1 ${grade.color}`}>{pct}%</p>
        <p className="text-slate-300 text-sm">{correct} / {total} 問正解</p>
        <span className={`inline-block mt-3 px-4 py-1 rounded-full text-sm font-semibold ${grade.color} border ${grade.border}`}>{grade.label}</span>
      </div>
      <div className="mb-8 space-y-2">
        <p className="text-xs font-semibold text-slate-400 uppercase tracking-widest mb-3">問題別結果</p>
        {results.map((r, i) => {
          const q = questions.find((q) => q.id === r.id);
          return (
            <div key={i} className={`flex items-center gap-3 p-3 rounded-xl border ${r.correct ? "bg-emerald-500/10 border-emerald-500/30" : "bg-rose-500/10 border-rose-500/30"}`}>
              <span className={`text-lg ${r.correct ? "text-emerald-400" : "text-rose-400"}`}>{r.correct ? "✓" : "✗"}</span>
              <div className="flex-1 min-w-0">
                <p className="text-xs text-slate-400">{q?.year}年 Q{q?.number}</p>
                <p className="text-sm text-slate-200 truncate">{q?.question.slice(0, 40)}…</p>
              </div>
            </div>
          );
        })}
      </div>
      <div className="space-y-3">
        <button onClick={onRetry} className="w-full py-4 rounded-2xl bg-emerald-500 hover:bg-emerald-400 active:scale-95 transition-all font-bold text-slate-900">もう一度挑戦</button>
        <button onClick={onHome} className="w-full py-4 rounded-2xl bg-slate-800 hover:bg-slate-700 border border-slate-700 active:scale-95 transition-all font-semibold text-slate-200">ホームへ戻る</button>
      </div>
    </div>
  );
}
